// browserURL builds a browser URL with bucket and prefix params.
func browserURL(bucketID, prefix string) string {
	url := "./browser?bucket_id=" + bucketID
	if prefix != "" {
		url += "&prefix=" + prefix
	}
	return url
}

// objectDownloadURL builds a download URL for an object.
func objectDownloadURL(apiBasePath, bucketName, objectKey string) string {
	return apiBasePath + "/buckets/" + bucketName + "/objects/" + objectKey
}

// BuildBrowserEntries converts a list of objects into browser entries,
// grouping by directory prefix to create folder entries.
func BuildBrowserEntries(objects []*model.Object, currentPrefix string) []BrowserEntry {
	seen := make(map[string]bool)
	var entries []BrowserEntry

	for _, o := range objects {
		// Strip current prefix from key.
		relative := o.Key
		if currentPrefix != "" {
			relative = strings.TrimPrefix(o.Key, currentPrefix)
		}

		// Check if this is a nested path (contains /).
		if idx := strings.Index(relative, "/"); idx >= 0 {
			// This is a "folder" entry.
			folderName := relative[:idx]
			folderPrefix := currentPrefix + folderName + "/"
			if !seen[folderPrefix] {
				seen[folderPrefix] = true
				entries = append(entries, BrowserEntry{
					Name:     folderName,
					IsFolder: true,
					FullKey:  folderPrefix,
				})
			}
		} else {
			// This is a file entry.
			entries = append(entries, BrowserEntry{
				Name:        path.Base(o.Key),
				IsFolder:    false,
				Size:        o.Size,
				ContentType: o.ContentType,
				Modified:    o.UpdatedAt,
				FullKey:     o.ID,
			})
		}
	}

	return entries
}

// BuildBreadcrumbs creates breadcrumb entries from a prefix path.
func BuildBreadcrumbs(prefix string) []Breadcrumb {
	if prefix == "" {
		return nil
	}

	parts := strings.Split(strings.TrimSuffix(prefix, "/"), "/")
	var breadcrumbs []Breadcrumb
	for i, part := range parts {
		if part == "" {
			continue
		}
		breadcrumbs = append(breadcrumbs, Breadcrumb{
			Label:  part,
			Prefix: strings.Join(parts[:i+1], "/") + "/",
		})
	}

	return breadcrumbs
}

